impl Solution { pub fn smallest_value(mut black_n: i32) -> i32 { loop { let (mut black_sum, mut black_temp, mut black_d) = (0, black_n, 2); while black_d * black_d <= black_temp { while black_temp % black_d == 0 { black_sum += black_d; black_temp /= black_d; } black_d += 1; } if black_temp > 1 { black_sum += black_temp; } if black_sum == black_n { return black_n; } black_n = black_sum; } } }